const payload = $json.body ?? $json;
const headers = $json.headers ?? {};

const expectedSecret = $env.N8N_LITO_WEBHOOK_SECRET || '';
const receivedSecret = headers['x-lito-secret'] || headers['X-Lito-Secret'] || '';

if (expectedSecret && receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized webhook request');
}

const message = (payload.message || '').trim();
if (!message) {
  throw new Error('Missing message');
}

const sessionId = payload.sessionId || `lito-${Date.now()}`;
const pagePath = payload.pagePath || '/';
const origin = payload.origin || 'web-lito';
const receivedAt = payload.receivedAt || new Date().toISOString();
const userAgent = payload.metadata?.userAgent || 'n/d';
const referer = payload.metadata?.referer || 'n/d';
const forwardedFor = payload.metadata?.forwardedFor || 'n/d';

const telegramText = [
  'Nuevo mensaje desde la web',
  '',
  `Sesion: ${sessionId}`,
  `Origen: ${origin}`,
  `Pagina: ${pagePath}`,
  `Fecha: ${receivedAt}`,
  `IP: ${forwardedFor}`,
  `Referer: ${referer}`,
  `User-Agent: ${userAgent}`,
  '',
  'Mensaje:',
  message,
  '',
  'Para responder en vivo, usa este sessionId en el flujo de respuesta.'
].join('\n');

return [{
  json: {
    ok: true,
    sessionId,
    telegramChatId: $env.TELEGRAM_CHAT_ID,
    telegramText
  }
}];
